<?php $editing=!!$post; ?><section class="admin-page-head"><div><p class="eyebrow">ATELIER / EDITOR</p><h1><?= $editing?'Editează articolul':'Articol nou' ?></h1></div><div class="button-row"><?php if($editing): ?><a class="admin-button secondary" href="<?= e(url('/admin/atelier/'.$post['id'].'/revisions')) ?>">Revizii</a><a class="admin-button secondary" target="_blank" href="<?= e(url('/atelier/'.$post['slug'])) ?>">Previzualizare ↗</a><?php endif; ?></div></section><?php if($notice): ?><div class="admin-alert success"><?= e($notice) ?></div><?php endif; ?><form class="admin-form-layout" enctype="multipart/form-data" data-editorial-editor method="post" action="<?= e(url($editing?'/admin/atelier/'.$post['id']:'/admin/atelier')) ?>"><?= csrf_field() ?><div><section class="admin-panel"><h2>Conținut</h2><label>Titlu<input name="title" required value="<?= e($post['title']??'') ?>"></label><label>Slug<input name="slug" value="<?= e($post['slug']??'') ?>" placeholder="generat automat"></label><label>Rezumat<textarea name="excerpt" maxlength="600"><?= e($post['excerpt']??'') ?></textarea></label><label>Conținut HTML<textarea name="content_html" rows="18" required><?= e($post['content_html']??'') ?></textarea></label><p class="help">HTML permis: paragrafe, subtitluri, liste, citate, linkuri și imagini sigure. Scripturile și atributele periculoase sunt eliminate.</p></section><section class="admin-panel seo-assistant" data-seo-assistant data-seo-kind="article"><div class="panel-head"><div><p class="eyebrow">OPTIMIZARE LOCALĂ</p><h2>SEO și social preview</h2><p class="help">Se actualizează inteligent din titlu, rezumat și conținut.</p></div><button class="admin-button secondary" type="button" data-seo-regenerate>↻ Regenerează</button></div><div class="seo-live-status"><span class="seo-pulse"></span><strong>Generator inteligent activ</strong><small>fără servicii externe</small></div><div class="admin-form-grid"><label class="wide">Meta title <span class="seo-counter" data-seo-title-count>0/60</span><input name="meta_title" maxlength="70" data-seo-title value="<?= e($post['meta_title']??'') ?>"></label><label class="wide">Meta description <span class="seo-counter" data-seo-description-count>0/160</span><textarea name="meta_description" maxlength="180" data-seo-description><?= e($post['meta_description']??'') ?></textarea></label><div class="seo-preview wide"><small>PREVIZUALIZARE GOOGLE</small><strong data-seo-preview-title>Titlul articolului</strong><span data-seo-preview-url><?= e(url('/atelier/'.($post['slug']??'articol'))) ?></span><p data-seo-preview-description>Descrierea articolului va apărea aici.</p></div><label class="wide">Canonical URL<input type="url" name="canonical_url" value="<?= e($post['canonical_url']??'') ?>" placeholder="gol = URL propriu"></label><label>OG title<input name="og_title" value="<?= e($post['og_title']??'') ?>"></label><label>OG description<textarea name="og_description"><?= e($post['og_description']??'') ?></textarea></label></div></section></div><aside><section class="admin-panel"><h2>Publicare</h2><label>Status<select name="status"><?php foreach(['draft'=>'Draft','in_review'=>'În revizie','scheduled'=>'Programat','published'=>'Publicat','archived'=>'Arhivat'] as $value=>$label): ?><option value="<?= e($value) ?>" <?= ($post['status']??'draft')===$value?'selected':'' ?>><?= e($label) ?></option><?php endforeach; ?></select></label><label>Data programată<input type="datetime-local" name="scheduled_at" value="<?= !empty($post['scheduled_at'])?date('Y-m-d\TH:i',strtotime($post['scheduled_at'])):'' ?>"></label><label class="check-label"><input type="checkbox" name="robots_index" value="1" <?= !isset($post['robots_index'])||$post['robots_index']?'checked':'' ?>> Index, follow</label><button class="admin-button" type="submit">Salvează articolul</button></section><section class="admin-panel"><h2>Categorii</h2><?php foreach($categories as $category): ?><label class="check-label"><input type="checkbox" name="categories[]" value="<?= (int)$category['id'] ?>" <?= in_array((int)$category['id'],$selected,true)?'checked':'' ?>> <?= e($category['name']) ?></label><?php endforeach; ?><label>Categorie principală<select name="primary_category_id"><option value="">Alege</option><?php foreach($categories as $category): ?><option value="<?= (int)$category['id'] ?>"><?= e($category['name']) ?></option><?php endforeach; ?></select></label></section><section class="admin-panel"><h2>Imagine principală</h2><?php if(!empty($post['image_path'])): ?><img class="admin-preview-image" src="<?= e(url($post['image_path'])) ?>" alt=""><?php endif; ?><input type="file" name="featured_image" accept="image/jpeg,image/png,image/webp"></section></aside></form>
